/// `texture_views_and_samplers` must contain one `(view, sampler)` per texture property in Properties order.
pub fn create_material_bind_group(
    device: &wgpu::Device,
    layout: &wgpu::BindGroupLayout,
    label: &str,
    material_uniform_buffer: &wgpu::Buffer,
    texture_views_and_samplers: &[(&wgpu::TextureView, &wgpu::Sampler)],
) -> wgpu::BindGroup {
    let mut entries: Vec<wgpu::BindGroupEntry> = Vec::new();
    entries.push(wgpu::BindGroupEntry {
        binding: 0,
        resource: wgpu::BindingResource::Buffer(wgpu::BufferBinding {
            buffer: material_uniform_buffer,
            offset: 0,
            size: None,
        }),
    });
    let mut b: u32 = 1;
    for (view, sampler) in texture_views_and_samplers {
        entries.push(wgpu::BindGroupEntry {
            binding: b,
            resource: wgpu::BindingResource::TextureView(view),
        });
        b += 1;
        entries.push(wgpu::BindGroupEntry {
            binding: b,
            resource: wgpu::BindingResource::Sampler(sampler),
        });
        b += 1;
    }
    device.create_bind_group(&wgpu::BindGroupDescriptor { label: Some(label), layout, entries: &entries })
}

